public class CommandInjectionSecure {

    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String userInput = br.readLine();

            // Validate user input to ensure it does not contain any malicious characters or commands
            if (!userInput.matches("[a-zA-Z0-9.-]+")) {
                System.out.println("Invalid command input. Please enter a valid command.");
                return;
            }

            // Execute the sanitized command using ProcessBuilder
            ProcessBuilder processBuilder = new ProcessBuilder("ping", userInput);
            Process process = processBuilder.start();

            BufferedReader inputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = inputReader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

